// Parse HTML and extract site content
const html = $input.first().json.body || '';

const items = [];
const titleMatch = html.match(/<title>(.*?)<\/title>/i);
const siteTitle = titleMatch ? titleMatch[1] : 'iodeck.ir';
const now = new Date().toISOString();

// Extract H2 sections as feed items
const h2Regex = /<h2[^>]*>([\s\S]*?)<\/h2>/gi;
let m;
while ((m = h2Regex.exec(html)) !== null) {
  const text = m[1].replace(/<[^>]*>/g, '').trim();
  if (text && text.length > 3) {
    items.push({
      title: text,
      description: 'Page section from iodeck.ir',
      link: 'https://iodeck.ir',
      pubDate: now
    });
  }
}

// Extract service cards
const cardRegex = /<h3[^>]*>([\s\S]*?)<\/h3>/gi;
while ((m = cardRegex.exec(html)) !== null) {
  const text = m[1].replace(/<[^>]*>/g, '').trim();
  if (text && text.length > 3 && !items.find(i => i.title === text)) {
    items.push({
      title: text,
      description: 'Service offered by iodeck.ir',
      link: 'https://iodeck.ir/pages/services.html',
      pubDate: now
    });
  }
}

return [{
  json: {
    feedTitle: siteTitle,
    feedLink: 'https://iodeck.ir',
    feedDesc: 'IODECK Digital Innovation - RSS Feed',
    items: items.slice(0, 20)
  }
}];

const data = $input.first().json;
const items = data.items || [];

let rss = `<?xml version="1.0" encoding="UTF-8"?>\n`;
rss += `<rss version="2.0" xmlns:atom="http://www.w3.org/2005/Atom">\n`;
rss += `<channel>\n`;
rss += `  <title>${data.feedTitle}</title>\n`;
rss += `  <link>${data.feedLink}</link>\n`;
rss += `  <description>${data.feedDesc}</description>\n`;
rss += `  <atom:link href="https://iodeck.ir/rss" rel="self" type="application/rss+xml"/>\n`;
rss += `  <lastBuildDate>${new Date().toUTCString()}</lastBuildDate>\n`;

items.forEach(item => {
  rss += `  <item>\n`;
  rss += `    <title>${item.title}</title>\n`;
  rss += `    <link>${item.link}</link>\n`;
  rss += `    <description>${item.description || ''}</description>\n`;
  rss += `    <pubDate>${new Date(item.pubDate).toUTCString()}</pubDate>\n`;
  rss += `  </item>\n`;
});

rss += `</channel>\n</rss>`;

return [{ json: { rss: rss } }];
